import { useState } from 'react';
import type { SortDescriptor } from 'react-aria-components';

function SortableTable() {
  const [sortDescriptor, setSortDescriptor] = useState<SortDescriptor>({
    column: 'name',
    direction: 'ascending',
  });

  const rows = [
    { id: '1', name: 'Alice', email: 'alice@example.com', role: 'Admin' },
    { id: '2', name: 'Bob', email: 'bob@example.com', role: 'Editor' },
  ];

  const sorted = [...rows].sort((a, b) => {
    const col = sortDescriptor.column as keyof typeof a;
    const cmp = a[col].localeCompare(b[col]);
    return sortDescriptor.direction === 'descending' ? -cmp : cmp;
  });

  return (
    <Table.Root
      aria-label="People"
      sortDescriptor={sortDescriptor}
      onSortChange={setSortDescriptor}
    >
      <Table.Header>
        <Table.Column id="name" isRowHeader allowsSorting>Name</Table.Column>
        <Table.Column id="email" allowsSorting>Email</Table.Column>
        <Table.Column id="role" allowsSorting>Role</Table.Column>
      </Table.Header>
      <Table.Body>
        {sorted.map((row) => (
          <Table.Row key={row.id} id={row.id}>
            <Table.Cell>{row.name}</Table.Cell>
            <Table.Cell>{row.email}</Table.Cell>
            <Table.Cell>{row.role}</Table.Cell>
          </Table.Row>
        ))}
      </Table.Body>
    </Table.Root>
  );
}

import { useState } from 'react';
import type { Selection } from 'react-aria-components';

function RemovableTags() {
  const [tags, setTags] = useState([
    { id: 'react', name: 'React' },
    { id: 'vue', name: 'Vue' },
    { id: 'angular', name: 'Angular' },
    { id: 'svelte', name: 'Svelte' },
  ]);

  const handleRemove = (keys: Selection) => {
    setTags((prev) => prev.filter((tag) => !(keys as Set<string>).has(tag.id)));
  };

  return (
    <TagGroup.Root onRemove={handleRemove}>
      <TagGroup.Label>Frameworks</TagGroup.Label>
      <TagGroup.List>
        {tags.map((tag) => (
          <TagGroup.Tag key={tag.id} id={tag.id}>{tag.name}</TagGroup.Tag>
        ))}
      </TagGroup.List>
    </TagGroup.Root>
  );
}

